@prefix ada: <https://ada.astromat.org/metadata/> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:DigitalDocument,
                        ada:document ;
                    schema1:isBasedOn "calibration_original_20230415.pdf" ;
                    schema1:version "1.0" ] ;
            sh:resultMessage "A document must have a componentType." ;
            sh:resultPath ada:componentType ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A document must have a componentType." ;
                    sh:minCount 1 ;
                    sh:path ada:componentType ] ] .

@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms true .
